const text = $('Atendente Virtual Mika').item.json.output || '';
const nomeMatch = text.match(/Nome do Cliente:\s*(.+)/);
const nomeCliente = nomeMatch ? nomeMatch[1].trim() : 'Cliente';
const dataMatch = text.match(/Data da Entrega:\s*(\d{2})\/(\d{2})\/(\d{4})/);
let dataEntrega = new Date().toISOString().split('T')[0];
if (dataMatch) { dataEntrega = dataMatch[3] + '-' + dataMatch[2] + '-' + dataMatch[1]; }
const massaMatch = text.match(/Massa:\s*(.+)/);
const saborBolo = massaMatch ? massaMatch[1].trim() : 'A definir';
const temPersonalizados = /topo de bolo|personalizado/i.test(text);
return { json: { nomeCliente, dataEntrega, saborBolo, possui_personalizados: temPersonalizados } };
